uint scaleDownRounding(uint srcVal, uint srcBits, uint dstBits) {
uint scaleBits = (srcBits - dstBits);
uint halfScaleRange = 1 << (scaleBits - 1);
uint shifted = (srcVal + halfScaleRange) >> scaleBits;
uint maxValue = (1 << dstBits) - 1;
if (shifted > maxValue) {
shifted = maxValue;
}
return shifted;
}
